function renderItemizedSection(sectionEl) {
  const sectionId = sectionEl.dataset.deductionSection;
  const storageKey = sectionEl.dataset.storageKey;
  const list = sectionEl.querySelector(".deduction-list");
  const items = getStoredItems(storageKey);
  const now = new Date();
  list.innerHTML = "";
  if (!items.length) { list.innerHTML = '<li class="text-slate-500 text-sm">No items added yet.</li>'; return; }
  items.forEach((item) => {
    const li = document.createElement("li");
    li.className = "rounded-lg border border-slate-200 p-3 bg-slate-50";
    const monthly = monthlyItemEquivalent(item, now);
    if (state.deductionConfirmDelete[sectionId] === item.id) {
      li.innerHTML = `<p class="text-sm text-rose-700 mb-2">Are you sure you want to delete this item?</p><div class="flex gap-2"><button data-deduction-action="confirm-delete" data-item-id="${item.id}" class="rounded bg-rose-600 text-white px-2 py-1 text-xs">Confirm Delete</button><button data-deduction-action="cancel-delete" class="rounded border border-slate-300 px-2 py-1 text-xs">Cancel</button></div>`;
    } else if (state.deductionEditing[sectionId] === item.id) {
      li.innerHTML = `<form data-deduction-inline-form="${item.id}" class="grid gap-2 sm:grid-cols-2"><input name="name" value="${(item.name||"").replace(/"/g,"&quot;")}" class="rounded border border-slate-300 px-2 py-1 text-sm" required /><input name="amount" type="number" min="0" step="0.01" value="${toMoneyNumber(item.amount)}" class="rounded border border-slate-300 px-2 py-1 text-sm" required /><select name="frequency" class="rounded border border-slate-300 px-2 py-1 text-sm"><option value="monthly" ${item.frequency==="monthly"?"selected":""}>Monthly</option><option value="yearly" ${item.frequency==="yearly"?"selected":""}>Yearly</option><option value="weekly" ${item.frequency==="weekly"?"selected":""}>Weekly</option><option value="onetime" ${item.frequency==="onetime"?"selected":""}>One-time</option></select><div class="${item.frequency==="onetime"?"":"hidden"}" data-inline-date-wrap><input name="dateReceived" type="date" value="${item.dateReceived||""}" class="rounded border border-slate-300 px-2 py-1 text-sm" /></div><div class="sm:col-span-2 flex gap-2"><button type="submit" class="rounded bg-blue-600 text-white px-2 py-1 text-xs">Save Changes</button><button data-deduction-action="cancel-edit" type="button" class="rounded border border-slate-300 px-2 py-1 text-xs">Cancel</button></div></form>`;
    } else {
      li.innerHTML = `<div class="flex items-start justify-between gap-2"><div><p class="font-medium">${item.name}</p><p class="text-sm text-slate-600">${formatCurrency(toMoneyNumber(item.amount))} • ${item.frequency}</p>${item.frequency==="onetime"&&item.dateReceived?`<p class="text-xs text-slate-500">Date: ${item.dateReceived}</p>`:""}<p class="text-sm text-slate-700">Monthly equivalent: ${formatCurrency(monthly)}</p></div><div class="flex gap-2"><button data-deduction-action="edit" data-item-id="${item.id}" class="rounded border border-slate-300 px-2 py-1 text-xs">Edit</button><button data-deduction-action="delete" data-item-id="${item.id}" class="rounded bg-rose-600 text-white px-2 py-1 text-xs">Delete</button></div></div>`;
    }
    list.appendChild(li);
  });
}
function renderDeductionSections() { els.fdDeductionSections?.forEach(renderItemizedSection); }
function getDeductionsMonthlyTotal() { return DEDUCTION_SECTIONS.reduce((sum, section) => sum + getStoredItems(section.storageKey).reduce((sectionSum, item) => sectionSum + monthlyItemEquivalent(item), 0), 0); }
function monthlyIncomeEquivalent(src, now = new Date()) { const a = toMoneyNumber(src.amount); if (src.frequency === "yearly") return a / 12; if (src.frequency === "weekly") return (a * 52) / 12; if (src.frequency === "onetime") { const d = new Date(src.dateReceived || ""); return (!Number.isNaN(d.getTime()) && d.getFullYear() === now.getFullYear() && d.getMonth() === now.getMonth()) ? a : 0; } return a; }

