function getDashboardInputs(){ const p=appState.currentUser&&appState.dataLoaded?appState.userData.dashboardSettings||{}:readLocalObject(DASHBOARD_STORAGE_KEY,{}); return { taxAmount:toMoneyNumber(p.taxAmount), taxType:["monthly","yearly","percentage"].includes(p.taxType)?p.taxType:"monthly", detailsCollapsed: typeof p.detailsCollapsed === "boolean" ? p.detailsCollapsed : undefined };}
function saveDashboardInputs(v){const next={...(appState.userData.dashboardSettings||{}),...v};appState.userData.dashboardSettings=next;writeLocalObject(DASHBOARD_STORAGE_KEY,next);if(appState.currentUser&&appState.db)setDoc(userDocRef("dashboardSettings","preferences"),next,{merge:true}).catch((error)=>{console.error(error);setAuthError("We could not save dashboard settings to Firestore. They are still saved locally as a fallback.");});}
function setDashboardFormValues(v){ if(!els.fdForm) return; els.fdTaxAmount.value=v.taxAmount||""; els.fdTaxType.value=v.taxType; }
const getDashboardFormValues=()=>({ taxAmount:toMoneyNumber(els.fdTaxAmount?.value), taxType:els.fdTaxType?.value||"monthly" });
const getDashboardDetailsCollapsed=()=>{const settings=getDashboardInputs();return typeof settings.detailsCollapsed==="boolean"?settings.detailsCollapsed:localStorage.getItem(DASHBOARD_DETAILS_COLLAPSED_KEY)!=="false";};
function setDashboardDetailsCollapsed(isCollapsed){localStorage.setItem(DASHBOARD_DETAILS_COLLAPSED_KEY,String(isCollapsed));saveDashboardInputs({detailsCollapsed:isCollapsed});if(!els.fdDetailsContent||!els.fdDetailsToggle)return;els.fdDetailsContent.classList.toggle("hidden",isCollapsed);els.fdDetailsToggle.textContent=isCollapsed?"Show Details":"Hide Details";}

function filterByPeriod(txns){ const p=PERIOD_FILTERS.includes(els.periodSelect.value)?els.periodSelect.value:"all"; if(p==="all") return txns; const now=new Date(); return txns.filter((t)=>{ const d=new Date(t.purchaseAt); if(p==="daily") return d.toDateString()===now.toDateString(); if(p==="weekly") return now.getTime()-d.getTime()<=604800000&&now.getTime()>=d.getTime(); if(p==="monthly") return d.getFullYear()===now.getFullYear()&&d.getMonth()===now.getMonth(); return d.getFullYear()===now.getFullYear(); }); }
const sortedTxns=(txns)=>{ const f=els.sortOrderSelect.value==="oldest"?1:-1; return [...txns].sort((a,b)=>(new Date(a.purchaseAt)-new Date(b.purchaseAt))*f); };
function renderSummary(txns){ const filtered=filterByPeriod(txns); els.totalSpent.textContent=formatCurrency(filtered.reduce((s,t)=>s+t.amount,0)); els.transactionCount.textContent=String(filtered.length); const totals=Object.fromEntries(CATEGORIES.map((c)=>[c,0])); filtered.forEach((t)=>totals[t.category]+=t.amount); els.categorySummary.innerHTML=""; CATEGORIES.forEach((c)=>{ const li=document.createElement("li"); li.className="flex justify-between rounded-md border border-slate-200 px-3 py-2 bg-white"; li.textContent=`${c}: ${formatCurrency(totals[c])}`; els.categorySummary.appendChild(li); }); }
function normalizeCreditCard(card) {
  const legacyDueDate = typeof card.dueDate === "string" ? new Date(card.dueDate) : null;
  const dueDayValue = toMoneyNumber(card.dueDay) || (legacyDueDate && !Number.isNaN(legacyDueDate.getTime()) ? legacyDueDate.getDate() : 1);
  return {
    id: typeof card.id === "string" ? card.id : generateTransactionId(),
    cardName: typeof card.cardName === "string" && card.cardName.trim() ? card.cardName.trim() : "Unnamed card",
    limit: toMoneyNumber(card.limit),
    balance: toMoneyNumber(card.balance),
    dueDay: Math.min(31, Math.max(1, Math.round(dueDayValue)))
  };
}
function getCreditCards(){const cards=getCachedCollection("creditCards");if(cards.length)return cards.map(normalizeCreditCard);const legacy=readLocalObject(LEGACY_CREDIT_CARD_STORAGE_KEY,null);if(!legacy||(!legacy.cardName&&!legacy.limit&&!legacy.balance))return[];return[normalizeCreditCard({cardName:legacy.cardName||"Credit Card",limit:legacy.limit,balance:legacy.balance,dueDay:legacy.dueDay||1})];}
function saveCreditCards(cards){setCachedCollection("creditCards",cards.map(normalizeCreditCard));}
function getCreditCardName(id){const card=getCreditCards().find((c)=>c.id===id);return card?card.cardName:"Uncategorized credit spending";}
function getCurrentMonthCreditTransactions(txns){const now=new Date();return txns.filter((t)=>{const d=new Date(t.purchaseAt);return t.paymentMethod==="Credit Card"&&t.amount>0&&d.getFullYear()===now.getFullYear()&&d.getMonth()===now.getMonth();});}
function getCreditCardMetrics(txns){const cards=getCreditCards();const creditTransactions=getCurrentMonthCreditTransactions(txns);const cardMetrics=cards.map((card)=>{const cardTxns=creditTransactions.filter((t)=>t.creditCardId===card.id);const creditSpentMonth=cardTxns.reduce((sum,t)=>sum+Number(t.amount),0);const totalUsed=card.balance+creditSpentMonth;const creditLeft=card.limit-totalUsed;const utilization=card.limit>0?(totalUsed/card.limit)*100:0;return{...card,creditTransactions:cardTxns,creditSpentMonth,totalUsed,creditLeft,utilization};});const uncategorizedSpent=creditTransactions.filter((t)=>!t.creditCardId||!cards.some((c)=>c.id===t.creditCardId)).reduce((sum,t)=>sum+Number(t.amount),0);const totalLimit=cardMetrics.reduce((s,c)=>s+c.limit,0);const totalUsed=cardMetrics.reduce((s,c)=>s+c.totalUsed,0)+uncategorizedSpent;const totalCreditLeft=totalLimit-totalUsed;const totalCreditSpentMonth=cardMetrics.reduce((s,c)=>s+c.creditSpentMonth,0)+uncategorizedSpent;const averageUtilization=cardMetrics.length?cardMetrics.reduce((s,c)=>s+c.utilization,0)/cardMetrics.length:0;return{cards:cardMetrics,creditTransactions,uncategorizedSpent,totalLimit,totalUsed,totalCreditLeft,totalCreditSpentMonth,averageUtilization};}
function renderCreditCardOptions(){const cards=getCreditCards();if(els.creditCardUsed){const current=els.creditCardUsed.value;els.creditCardUsed.innerHTML='<option value="">Uncategorized credit spending</option>'+cards.map((c)=>`<option value="${c.id}">${escapeHtml(c.cardName)}</option>`).join("");els.creditCardUsed.value=cards.some((c)=>c.id===current)?current:"";}if(els.noCreditCardsMessage)els.noCreditCardsMessage.classList.toggle("hidden",!(els.spentOnCreditCard?.checked&&!cards.length));}
function setTransactionCreditCardVisibility(){if(!els.creditCardUsedWrap)return;const isCredit=Boolean(els.spentOnCreditCard?.checked);els.creditCardUsedWrap.classList.toggle("hidden",!isCredit);if(!isCredit&&els.creditCardUsed)els.creditCardUsed.value="";if(els.noCreditCardsMessage)els.noCreditCardsMessage.classList.toggle("hidden",!(isCredit&&!getCreditCards().length));}
function renderCreditCardTracker(txns,moneyLeftMonth=0){if(!els.ccCardList)return;const metrics=getCreditCardMetrics(txns);els.ccTotalLimit.textContent=formatCurrency(metrics.totalLimit);els.ccTotalUsed.textContent=formatCurrency(metrics.totalUsed);els.ccTotalLeft.textContent=formatCurrency(metrics.totalCreditLeft);els.ccAverageUtilization.textContent=`${metrics.averageUtilization.toFixed(0)}%`;els.ccSpentMonth.textContent=formatCurrency(metrics.totalCreditSpentMonth);els.fdCreditUsed.textContent=formatCurrency(metrics.totalUsed);els.fdCreditLeft.textContent=formatCurrency(metrics.totalCreditLeft);els.fdCreditUtilization.textContent=`${metrics.averageUtilization.toFixed(0)}%`;els.ccWarnings.innerHTML="";metrics.cards.filter((c)=>c.utilization>70).forEach((c)=>{const div=document.createElement("div");div.className="rounded-lg border border-amber-200 bg-amber-50 p-3 text-sm text-amber-800";div.textContent=`High utilization on ${c.cardName}. Try to keep credit utilization below 70%.`;els.ccWarnings.appendChild(div);});metrics.cards.filter((c)=>c.creditLeft<0).forEach((c)=>{const div=document.createElement("div");div.className="rounded-lg border border-rose-200 bg-rose-50 p-3 text-sm text-rose-800";div.textContent=`${c.cardName} has exceeded its credit limit.`;els.ccWarnings.appendChild(div);});if(metrics.totalCreditSpentMonth>moneyLeftMonth){const div=document.createElement("div");div.className="rounded-lg border border-amber-200 bg-amber-50 p-3 text-sm text-amber-800";div.textContent="Your credit card spending is higher than your remaining monthly budget.";els.ccWarnings.appendChild(div);}els.ccCardList.innerHTML="";if(!metrics.cards.length){els.ccCardList.innerHTML='<li class="rounded-lg border border-dashed border-slate-300 p-3 text-sm text-slate-500">No credit cards added yet.</li>';}metrics.cards.forEach((card)=>{const li=document.createElement("li");li.className="rounded-lg border border-slate-200 bg-slate-50 p-3";if(state.creditCardConfirmDeleteId===card.id){li.innerHTML=`<p class="text-sm text-rose-700 mb-2">Are you sure you want to delete this credit card?</p><div class="flex gap-2"><button data-cc-action="confirm-delete" data-card-id="${card.id}" class="rounded bg-rose-600 text-white px-2 py-1 text-xs">Confirm Delete</button><button data-cc-action="cancel-delete" class="rounded border border-slate-300 px-2 py-1 text-xs">Cancel</button></div>`;}else if(state.creditCardEditingId===card.id){li.innerHTML=`<form data-cc-inline-form="${card.id}" class="grid gap-2 sm:grid-cols-2"><div><label class="block text-xs text-slate-500 mb-1">Card name</label><input name="cardName" value="${escapeHtml(card.cardName)}" class="w-full rounded border border-slate-300 px-2 py-1 text-sm" required /></div><div><label class="block text-xs text-slate-500 mb-1">Credit limit</label><input name="limit" type="number" min="0" step="0.01" value="${card.limit}" class="w-full rounded border border-slate-300 px-2 py-1 text-sm" required /></div><div><label class="block text-xs text-slate-500 mb-1">Current / previous balance</label><input name="balance" type="number" min="0" step="0.01" value="${card.balance}" class="w-full rounded border border-slate-300 px-2 py-1 text-sm" /></div><div><label class="block text-xs text-slate-500 mb-1">Monthly payment due day</label><input name="dueDay" type="number" min="1" max="31" step="1" value="${card.dueDay}" class="w-full rounded border border-slate-300 px-2 py-1 text-sm" /></div><div class="sm:col-span-2 flex gap-2"><button type="submit" class="rounded bg-blue-600 text-white px-2 py-1 text-xs">Save Changes</button><button type="button" data-cc-action="cancel-edit" class="rounded border border-slate-300 px-2 py-1 text-xs">Cancel</button></div></form>`;}else{li.innerHTML=`<div class="flex flex-wrap items-start justify-between gap-3"><div><p class="font-medium">${escapeHtml(card.cardName)}</p><div class="mt-1 grid gap-1 text-sm text-slate-600 sm:grid-cols-2 lg:grid-cols-4"><p>Credit limit: <strong>${formatCurrency(card.limit)}</strong></p><p>Current / previous balance: <strong>${formatCurrency(card.balance)}</strong></p><p>Credit spent this month: <strong>${formatCurrency(card.creditSpentMonth)}</strong></p><p>Total credit used: <strong>${formatCurrency(card.totalUsed)}</strong></p><p>Credit left: <strong>${formatCurrency(card.creditLeft)}</strong></p><p>Utilization: <strong>${card.utilization.toFixed(0)}%</strong></p><p>Monthly payment due day: <strong>${card.dueDay}</strong></p></div></div><div class="flex gap-2"><button data-cc-action="edit" data-card-id="${card.id}" class="rounded border border-slate-300 bg-white px-2 py-1 text-xs">Edit</button><button data-cc-action="delete" data-card-id="${card.id}" class="rounded bg-rose-600 px-2 py-1 text-xs text-white">Delete</button></div></div>`;}els.ccCardList.appendChild(li);});els.ccTransactionList.innerHTML="";if(!metrics.creditTransactions.length){els.ccTransactionList.innerHTML='<li class="text-slate-500">No credit card transactions this month.</li>';return;}metrics.creditTransactions.forEach((t)=>{const li=document.createElement("li");li.className="rounded-lg border border-slate-200 bg-slate-50 px-3 py-2";li.textContent=`${t.description} — ${formatCurrency(t.amount)} — ${getCreditCardName(t.creditCardId)} — ${new Date(t.purchaseAt).toLocaleDateString()}`;els.ccTransactionList.appendChild(li);});}
function renderFinancialDashboard(txns){ if(!els.fdMonthlyIncome) return; const i=getDashboardFormValues(); const income=getIncomeSources().reduce((s,src)=>s+monthlyIncomeEquivalent(src),0); const taxes=i.taxType==="yearly"?i.taxAmount/12:i.taxType==="percentage"?income*(i.taxAmount/100):i.taxAmount; const deductions=taxes+getDeductionsMonthlyTotal(); const plannedBudget=income-deductions; const now=new Date(); const spentMonth=txns.filter((t)=>{ const d=new Date(t.purchaseAt); return d.getFullYear()===now.getFullYear()&&d.getMonth()===now.getMonth()&&t.amount>0; }).reduce((s,t)=>s+Number(t.amount),0); const moneyLeftMonth=plannedBudget-spentMonth; const daysLeft=new Date(now.getFullYear(),now.getMonth()+1,0).getDate()-now.getDate()+1; const plannedDaily=daysLeft>0?moneyLeftMonth/daysLeft:moneyLeftMonth; const spentToday=txns.filter((t)=>{ const d=new Date(t.purchaseAt); return d.toDateString()===now.toDateString()&&t.amount>0; }).reduce((s,t)=>s+Number(t.amount),0); const moneyLeftToday=plannedDaily-spentToday; const savedToday=Math.max(moneyLeftToday,0); els.fdMonthlyIncome.textContent=formatCurrency(income); els.fdMonthlyExpendable.textContent=formatCurrency(plannedBudget); els.fdSpentMonth.textContent=formatCurrency(spentMonth); els.fdRemaining.textContent=formatCurrency(moneyLeftMonth); els.fdSafeToday.textContent=formatCurrency(plannedDaily); els.fdDailyBudget.textContent=formatCurrency(plannedDaily); els.fdSpentToday.textContent=formatCurrency(spentToday); els.fdLeftToday.textContent=formatCurrency(moneyLeftToday); els.fdSavedToday.textContent=formatCurrency(savedToday); els.fdRemaining.classList.toggle("text-rose-600",moneyLeftMonth<0); els.fdLeftToday.classList.toggle("text-rose-600",moneyLeftToday<0); els.fdMonthWarning.classList.toggle("hidden",moneyLeftMonth>=0); els.fdDayWarning.classList.toggle("hidden",moneyLeftToday>=0); renderCreditCardTracker(txns,moneyLeftMonth); }

function buildTrendSeries(txns,range){ const s=txns.map((t)=>({amount:Number(t.amount),date:new Date(t.purchaseAt)})).filter((t)=>Number.isFinite(t.amount)&&t.amount>0&&!Number.isNaN(t.date.getTime())); if(!s.length) return []; const now=new Date(); const b=new Map(); if(range==="week"){ const labels=["Sun","Mon","Tue","Wed","Thu","Fri","Sat"]; labels.forEach((l)=>b.set(l,0)); const start=new Date(now); start.setDate(now.getDate()-now.getDay()); start.setHours(0,0,0,0); s.forEach((t)=>{ const diff=Math.floor((t.date-start)/86400000); if(diff>=0&&diff<7){ const k=labels[t.date.getDay()]; b.set(k,(b.get(k)||0)+t.amount); }}); return labels.map((label)=>({label,amount:b.get(label)||0})); } if(range==="month"){ const y=now.getFullYear(),m=now.getMonth(),days=new Date(y,m+1,0).getDate(); for(let d=1; d<=days; d++) b.set(String(d),0); s.forEach((t)=>{ if(t.date.getFullYear()===y&&t.date.getMonth()===m){ const k=String(t.date.getDate()); b.set(k,(b.get(k)||0)+t.amount); }}); return Array.from(b,([label,amount])=>({label,amount})); } const months=["Jan","Feb","Mar","Apr","May","Jun","Jul","Aug","Sep","Oct","Nov","Dec"]; months.forEach((m)=>b.set(m,0)); s.forEach((t)=>{ if(t.date.getFullYear()===now.getFullYear()){ const k=months[t.date.getMonth()]; b.set(k,(b.get(k)||0)+t.amount); }}); return months.map((label)=>({label,amount:b.get(label)||0})); }
function renderTrend(txns){ const range=TREND_RANGES.includes(els.trendRangeSelect.value)?els.trendRangeSelect.value:"week"; const data=buildTrendSeries(txns,range).filter((d)=>d.amount>0); const emptyEl=$("trend-empty"),chartEl=$("trend-chart"); if(!emptyEl||!chartEl||!window.Recharts||!window.React||!window.ReactDOM) return; emptyEl.classList.toggle("hidden",data.length!==0); chartEl.classList.toggle("hidden",data.length===0); if(!data.length){ if(trendChartRoot?.unmount){ trendChartRoot.unmount(); trendChartRoot=null;} return;} const {ResponsiveContainer,AreaChart,Area,XAxis,YAxis,CartesianGrid,Tooltip}=window.Recharts; const e=window.React.createElement; const chartNode=e(ResponsiveContainer,{width:"100%",height:"100%"},e(AreaChart,{data,margin:{top:12,right:12,left:4,bottom:8}},e(CartesianGrid,{strokeDasharray:"3 3",stroke:"#e2e8f0"}),e(XAxis,{dataKey:"label",tick:{fontSize:12,fill:"#475569"}}),e(YAxis,{tickFormatter:(v)=>`$${Number(v).toFixed(0)}`,tick:{fontSize:12,fill:"#475569"},width:56}),e(Tooltip,{formatter:(v)=>formatCurrency(Number(v)||0),labelStyle:{color:"#0f172a"}}),e(Area,{type:"monotone",dataKey:"amount",stroke:"#2563eb",fill:"#93c5fd",fillOpacity:0.35,strokeWidth:3}))); if(typeof window.ReactDOM.createRoot==="function"){ if(!trendChartRoot) trendChartRoot=window.ReactDOM.createRoot(chartEl); trendChartRoot.render(chartNode);} else if(typeof window.ReactDOM.render==="function"){ window.ReactDOM.render(chartNode,chartEl);} }

function renderInlineEditCard(li,t){const dt=splitDateTime(t.purchaseAt);const cards=getCreditCards();const isCredit=t.paymentMethod==="Credit Card";const cardSelect=`<div data-inline-credit-card-wrap class="${isCredit?"":"hidden"}"><label class="block text-xs font-medium text-slate-600 mb-1">Credit Card Used</label><select name="creditCardId" class="w-full rounded-lg border border-slate-300 px-3 py-2 text-sm"><option value="">Uncategorized credit spending</option>${cards.map((c)=>`<option value="${c.id}" ${c.id===t.creditCardId?"selected":""}>${escapeHtml(c.cardName)}</option>`).join("")}</select>${cards.length?"":'<p class="mt-1 text-xs text-amber-700">No credit cards added yet. Add one in Advanced Mode.</p>'}</div>`;li.innerHTML=`<form class="w-full grid gap-3" data-inline-form="${t.id}"><div class="grid gap-3 sm:grid-cols-2"><div><label class="block text-xs font-medium text-slate-600 mb-1">Amount ($)</label><input name="amount" type="number" min="0" step="0.01" required value="${t.amount}" class="w-full rounded-lg border border-slate-300 px-3 py-2 text-sm" /></div><div><label class="block text-xs font-medium text-slate-600 mb-1">Category</label><select name="category" class="w-full rounded-lg border border-slate-300 px-3 py-2 text-sm">${CATEGORIES.map((c)=>`<option ${c===t.category?"selected":""}>${c}</option>`).join("")}</select></div><div class="rounded-lg border border-slate-200 bg-white px-3 py-2"><label class="flex items-center gap-2 text-xs font-medium text-slate-700"><input name="spentOnCreditCard" type="checkbox" ${isCredit?"checked":""} class="h-4 w-4 rounded border-slate-300 text-blue-600" />Spent on Credit Card</label></div>${cardSelect}</div><div><label class="block text-xs font-medium text-slate-600 mb-1">Description</label><input name="description" type="text" required value="${escapeHtml(t.description)}" class="w-full rounded-lg border border-slate-300 px-3 py-2 text-sm" /></div><div class="grid gap-3 sm:grid-cols-2"><div><label class="block text-xs font-medium text-slate-600 mb-1">Date of Purchase</label><input name="purchaseDate" type="date" required value="${dt.date}" class="w-full rounded-lg border border-slate-300 px-3 py-2 text-sm" /></div><div><label class="block text-xs font-medium text-slate-600 mb-1">Time of Purchase</label><input name="purchaseTime" type="time" required value="${dt.time}" class="w-full rounded-lg border border-slate-300 px-3 py-2 text-sm" /></div></div><div class="flex flex-wrap gap-2"><button type="submit" class="rounded-lg bg-blue-600 px-3 py-2 text-white text-sm">Save Changes</button><button type="button" data-action="cancel-inline-edit" class="rounded-lg border border-slate-300 bg-white px-3 py-2 text-sm">Cancel</button><button type="button" data-action="request-delete" data-id="${t.id}" class="rounded-lg bg-rose-600 px-3 py-2 text-white text-sm">Delete</button></div></form>`;}
function renderInlineDeleteConfirm(li,t){li.innerHTML=`<div class="w-full rounded-lg border border-rose-200 bg-rose-50 p-4"><p class="text-sm text-rose-800 font-medium">Are you sure you want to delete this transaction?</p><p class="text-xs text-rose-700 mt-1">${t.description} • ${formatCurrency(t.amount)}</p><div class="mt-3 flex gap-2"><button type="button" data-action="confirm-delete" data-id="${t.id}" class="rounded-lg bg-rose-600 px-3 py-2 text-white text-sm">Confirm Delete</button><button type="button" data-action="cancel-delete" class="rounded-lg border border-slate-300 bg-white px-3 py-2 text-sm">Cancel</button></div></div>`;}
function renderTransactions(txns){els.transactionList.innerHTML="";els.emptyState.style.display=txns.length?"none":"block";txns.forEach((t)=>{const li=document.createElement("li");li.className="rounded-lg border border-slate-200 p-3 sm:p-4 bg-slate-50";if(state.inlineEditingId===t.id){state.confirmDeleteId===t.id?renderInlineDeleteConfirm(li,t):renderInlineEditCard(li,t);els.transactionList.appendChild(li);return;}const row=document.createElement("div");row.className="flex items-start justify-between gap-4";const left=document.createElement("div");const cardLine=t.paymentMethod==="Credit Card"&&t.creditCardId?`<p class="text-sm text-slate-500">Card: ${escapeHtml(getCreditCardName(t.creditCardId))}</p>`:"";left.innerHTML=`<p class="font-semibold text-lg">${formatCurrency(t.amount)}</p><p>${escapeHtml(t.description)}</p><p class="text-sm text-slate-500">Category: ${escapeHtml(t.category)}</p><p class="text-sm text-slate-500">Payment: ${escapeHtml(t.paymentMethod)}</p>${cardLine}<p class="text-sm text-slate-500">${new Date(t.purchaseAt).toLocaleString()}</p>`;const actions=document.createElement("div");actions.className="flex gap-2";const edit=document.createElement("button");edit.type="button";edit.textContent="Edit";edit.className="rounded-lg border border-slate-300 bg-white px-3 py-2 text-sm";edit.dataset.action="edit";edit.dataset.id=t.id;actions.append(edit);row.append(left,actions);li.appendChild(row);els.transactionList.appendChild(li);});}


function setAdvancedMode(isAdvanced, options = {}){state.isAdvancedMode=Boolean(isAdvanced);els.simpleMode?.classList.toggle("hidden",state.isAdvancedMode);els.advancedMode?.classList.toggle("hidden",!state.isAdvancedMode);if(options.scroll){const target=state.isAdvancedMode?els.financialDashboard:els.simpleMode;target?.scrollIntoView({behavior:"smooth",block:"start"});}}
function bindNavigation(){els.openAdvanced?.addEventListener("click",()=>setAdvancedMode(true,{scroll:true}));els.backSimple?.addEventListener("click",()=>setAdvancedMode(false,{scroll:true}));}
function render(){const txns=sortedTxns(getTransactions().map(normalizeTransaction));state.transactionMap=new Map(txns.map((t)=>[t.id,t]));setAdvancedMode(state.isAdvancedMode);renderCreditCardOptions();setTransactionCreditCardVisibility();renderTransactions(txns);renderSummary(txns);renderTrend(txns);renderIncomeSources();renderDeductionSections();renderFinancialDashboard(txns);} 
function setDefaultDateTime(){const now=new Date();els.purchaseDate.value=now.toISOString().slice(0,10);els.purchaseTime.value=now.toTimeString().slice(0,5);} 

function bind(){
  els.googleSignIn?.addEventListener("click",async()=>{setAuthError("");if(!appState.auth){setAuthError("Firebase is not configured yet. Add your Firebase web app config values before signing in.");return;}const provider=new GoogleAuthProvider();try{await signInWithPopup(appState.auth,provider);}catch(error){console.error(error);setAuthError("Google sign-in failed. Please try again.");}});
  els.signOut?.addEventListener("click",async()=>{if(appState.auth)await signOut(appState.auth);});
  els.description.addEventListener("input",()=>{const c=categorize(els.description.value.trim());els.categoryPreview.textContent=`Category preview: ${c}`;els.category.value=c;});
  els.sortOrderSelect.addEventListener("change",render);els.periodSelect.addEventListener("change",render);els.trendRangeSelect.addEventListener("change",render);
  if(els.fdForm) els.fdForm.addEventListener("input",()=>{saveDashboardInputs(getDashboardFormValues());render();});
  els.spentOnCreditCard.addEventListener("change",setTransactionCreditCardVisibility);
  if(els.creditCardUsed) els.creditCardUsed.addEventListener("change",()=>{});
  if(els.ccForm){
    const setCreditCardFormOpen=(open)=>{els.ccForm.classList.toggle("hidden",!open);els.ccAddCard.textContent=open?"Close Credit Card Form":"+ Add Credit Card";};
    const resetCreditCardForm=()=>{els.ccForm.reset();};
    setCreditCardFormOpen(false);
    els.ccAddCard.addEventListener("click",()=>setCreditCardFormOpen(els.ccForm.classList.contains("hidden")));
    els.ccCancelAdd.addEventListener("click",()=>{resetCreditCardForm();setCreditCardFormOpen(false);});
    els.ccForm.addEventListener("submit",(e)=>{e.preventDefault();const rawName=els.ccCardName.value.trim();const card=normalizeCreditCard({id:generateTransactionId(),cardName:rawName,limit:els.ccLimit.value,balance:els.ccBalance.value,dueDay:els.ccDueDay.value});if(!rawName||card.limit<=0)return;saveCreditCards([...getCreditCards(),card]);resetCreditCardForm();setCreditCardFormOpen(false);render();});
    els.ccCardList.addEventListener("click",(e)=>{const b=e.target.closest("button[data-cc-action]");if(!b)return;const action=b.dataset.ccAction,id=b.dataset.cardId;if(action==="edit"&&id){state.creditCardEditingId=id;state.creditCardConfirmDeleteId=null;render();return;}if(action==="cancel-edit"){state.creditCardEditingId=null;render();return;}if(action==="delete"&&id){state.creditCardConfirmDeleteId=id;render();return;}if(action==="cancel-delete"){state.creditCardConfirmDeleteId=null;render();return;}if(action==="confirm-delete"&&id){saveCreditCards(getCreditCards().filter((c)=>c.id!==id));saveTransactions(getTransactions().map(normalizeTransaction).map((t)=>t.creditCardId===id?{...t,creditCardId:""}:t));state.creditCardConfirmDeleteId=null;state.creditCardEditingId=null;render();}});
    els.ccCardList.addEventListener("submit",(e)=>{const f=e.target.closest("form[data-cc-inline-form]");if(!f)return;e.preventDefault();const id=f.dataset.ccInlineForm;const fd=new FormData(f);const rawName=String(fd.get("cardName")||"").trim();const card=normalizeCreditCard({id,cardName:rawName,limit:fd.get("limit"),balance:fd.get("balance"),dueDay:fd.get("dueDay")});if(!rawName||card.limit<=0)return;saveCreditCards(getCreditCards().map((c)=>c.id===id?card:c));state.creditCardEditingId=null;render();});
  }
  if(els.fdDetailsToggle){setDashboardDetailsCollapsed(getDashboardDetailsCollapsed());els.fdDetailsToggle.addEventListener("click",()=>setDashboardDetailsCollapsed(!els.fdDetailsContent.classList.contains("hidden")));}
  els.fdDeductionSections?.forEach((sectionEl)=>{
    const storageKey=sectionEl.dataset.storageKey, sectionId=sectionEl.dataset.deductionSection, addBtn=sectionEl.querySelector(".deduction-add"), wrap=sectionEl.querySelector(".deduction-form-wrap"), form=sectionEl.querySelector(".deduction-form"), dateWrap=sectionEl.querySelector(".deduction-date-wrap"), cancelBtn=sectionEl.querySelector(".deduction-cancel"), list=sectionEl.querySelector(".deduction-list");
    const defaultAddLabel=addBtn.textContent;
    const setOpen=(open)=>{wrap.classList.toggle("hidden",!open);addBtn.textContent=open?"Close Form":defaultAddLabel;};
    const reset=()=>{form.reset();dateWrap.classList.add("hidden");};
    setOpen(false);
    addBtn.addEventListener("click",()=>setOpen(wrap.classList.contains("hidden")));
    form.elements.frequency.addEventListener("change",()=>dateWrap.classList.toggle("hidden",form.elements.frequency.value!=="onetime"));
    cancelBtn.addEventListener("click",()=>{reset();setOpen(false);});
    form.addEventListener("submit",(e)=>{e.preventDefault();const item={id:generateTransactionId(),name:String(form.elements.name.value||"").trim(),amount:toMoneyNumber(form.elements.amount.value),frequency:form.elements.frequency.value,dateReceived:form.elements.frequency.value==="onetime"?form.elements.dateReceived.value:""};if(!item.name||item.amount<=0)return;saveStoredItems(storageKey,[...getStoredItems(storageKey),item]);reset();setOpen(false);render();});
    list.addEventListener("change",(e)=>{if(e.target.name!=="frequency")return;const f=e.target.closest("form[data-deduction-inline-form]");if(!f)return;const wrap=f.querySelector("[data-inline-date-wrap]");if(wrap)wrap.classList.toggle("hidden",e.target.value!=="onetime");});
    list.addEventListener("click",(e)=>{const b=e.target.closest("button[data-deduction-action]");if(!b)return;const action=b.dataset.deductionAction,id=b.dataset.itemId;if(action==="edit"&&id){state.deductionEditing[sectionId]=id;state.deductionConfirmDelete[sectionId]=null;render();return;}if(action==="cancel-edit"){state.deductionEditing[sectionId]=null;render();return;}if(action==="delete"&&id){state.deductionConfirmDelete[sectionId]=id;render();return;}if(action==="cancel-delete"){state.deductionConfirmDelete[sectionId]=null;render();return;}if(action==="confirm-delete"&&id){saveStoredItems(storageKey,getStoredItems(storageKey).filter((x)=>x.id!==id));state.deductionConfirmDelete[sectionId]=null;state.deductionEditing[sectionId]=null;render();}});
    list.addEventListener("submit",(e)=>{const f=e.target.closest("form[data-deduction-inline-form]");if(!f)return;e.preventDefault();const id=f.dataset.deductionInlineForm,fd=new FormData(f),item={id,name:String(fd.get("name")||"").trim(),amount:toMoneyNumber(fd.get("amount")),frequency:String(fd.get("frequency")||"monthly"),dateReceived:String(fd.get("dateReceived")||"")};if(!item.name||item.amount<=0)return;saveStoredItems(storageKey,getStoredItems(storageKey).map((x)=>x.id===id?item:x));state.deductionEditing[sectionId]=null;render();});
  });
  if(els.fdAddIncome){
    const setIncomeFormOpen=(isOpen)=>{els.fdIncomeFormWrap.classList.toggle("hidden",!isOpen);els.fdAddIncome.textContent=isOpen?"Close Income Source Form":"+ Add Income Source";};
    const clearIncomeForm=()=>{els.fdIncomeForm.reset();els.fdIncomeForm.dataset.editId="";els.fdIncomeDateWrap.classList.add("hidden");};
    setIncomeFormOpen(false);
    els.fdAddIncome.addEventListener("click",()=>setIncomeFormOpen(els.fdIncomeFormWrap.classList.contains("hidden")));
    els.fdIncomeFrequency.addEventListener("change",()=>els.fdIncomeDateWrap.classList.toggle("hidden",els.fdIncomeFrequency.value!=="onetime"));
    els.fdIncomeCancel.addEventListener("click",()=>{clearIncomeForm();setIncomeFormOpen(false);});
    els.fdIncomeForm.addEventListener("submit",(e)=>{e.preventDefault();const sources=getIncomeSources();const next={id:els.fdIncomeForm.dataset.editId||generateTransactionId(),name:(els.fdIncomeName.value||"").trim(),amount:toMoneyNumber(els.fdIncomeAmount.value),frequency:els.fdIncomeFrequency.value,dateReceived:els.fdIncomeFrequency.value==="onetime"?els.fdIncomeDate.value:""};if(!next.name||next.amount<=0) return;const updated=els.fdIncomeForm.dataset.editId?sources.map((s)=>s.id===next.id?next:s):[...sources,next];saveIncomeSources(updated);clearIncomeForm();setIncomeFormOpen(false);render();});
    els.fdIncomeList.addEventListener("click",(e)=>{const b=e.target.closest("button[data-income-action]");if(!b)return;const id=b.dataset.incomeId;const action=b.dataset.incomeAction;const sources=getIncomeSources();if(action==="edit"&&id){state.incomeEditingId=id;state.incomeConfirmDeleteId=null;render();return;}if(action==="cancel-edit"){state.incomeEditingId=null;render();return;}if(action==="delete"&&id){state.incomeConfirmDeleteId=id;render();return;}if(action==="cancel-delete"){state.incomeConfirmDeleteId=null;render();return;}if(action==="confirm-delete"&&id){saveIncomeSources(sources.filter((x)=>x.id!==id));state.incomeConfirmDeleteId=null;state.incomeEditingId=null;render();}});
    els.fdIncomeList.addEventListener("submit",(e)=>{const f=e.target.closest("form[data-income-inline-form]");if(!f)return;e.preventDefault();const id=f.dataset.incomeInlineForm;const fd=new FormData(f);const next={id,name:String(fd.get("name")||"").trim(),amount:toMoneyNumber(fd.get("amount")),frequency:String(fd.get("frequency")||"monthly"),dateReceived:String(fd.get("dateReceived")||"")};if(!next.name||next.amount<=0)return;saveIncomeSources(getIncomeSources().map((x)=>x.id===id?next:x));state.incomeEditingId=null;render();});
  }
  els.transactionList.addEventListener("click",(e)=>{const b=e.target.closest("button[data-action]");if(!b)return;const {action,id}=b.dataset;if(action==="edit"&&id){state.inlineEditingId=id;state.confirmDeleteId=null;render();return;}if(action==="cancel-inline-edit"){state.inlineEditingId=null;state.confirmDeleteId=null;render();return;}if(action==="request-delete"&&id){state.confirmDeleteId=id;render();return;}if(action==="cancel-delete"){state.confirmDeleteId=null;render();return;}if(action==="confirm-delete"&&id){saveTransactions(getTransactions().map(normalizeTransaction).filter((x)=>x.id!==id));state.inlineEditingId=null;state.confirmDeleteId=null;render();}});
  els.transactionList.addEventListener("change",(e)=>{if(e.target.name!=="spentOnCreditCard")return;const f=e.target.closest("form[data-inline-form]");if(!f)return;const wrap=f.querySelector("[data-inline-credit-card-wrap]");if(wrap)wrap.classList.toggle("hidden",!e.target.checked);if(!e.target.checked){const select=f.querySelector('select[name="creditCardId"]');if(select)select.value="";}});
  els.transactionList.addEventListener("submit",(e)=>{const f=e.target.closest("form[data-inline-form]");if(!f)return;e.preventDefault();const id=f.dataset.inlineForm;const existing=state.transactionMap.get(id);if(!existing)return;const fd=new FormData(f);const amount=Number(fd.get("amount"));const description=String(fd.get("description")||"").trim();const category=String(fd.get("category")||"Other");const spentOnCreditCard=fd.get("spentOnCreditCard")==="on";const paymentMethod=spentOnCreditCard?"Credit Card":"Cash";const creditCardId=spentOnCreditCard?String(fd.get("creditCardId")||""):"";const purchaseDate=String(fd.get("purchaseDate")||"");const purchaseTime=String(fd.get("purchaseTime")||"");if(!Number.isFinite(amount)||amount<=0||!description)return;const updated={...existing,amount,description,category:CATEGORIES.includes(category)?category:categorize(description),paymentMethod,creditCardId,purchaseAt:parsePurchaseDateTime(purchaseDate,purchaseTime)};saveTransactions(getTransactions().map(normalizeTransaction).map((t)=>t.id===id?updated:t));state.inlineEditingId=null;state.confirmDeleteId=null;render();});
  els.form.addEventListener("submit",(e)=>{e.preventDefault();const amount=Number(els.amount.value);const description=els.description.value.trim();if(!Number.isFinite(amount)||amount<=0||!description)return;const txns=getTransactions().map(normalizeTransaction);txns.push({id:generateTransactionId(),amount,description,category:CATEGORIES.includes(els.category.value)?els.category.value:categorize(description),paymentMethod:els.spentOnCreditCard.checked?"Credit Card":"Cash",creditCardId:els.spentOnCreditCard.checked?els.creditCardUsed.value:"",purchaseAt:parsePurchaseDateTime(els.purchaseDate.value,els.purchaseTime.value),createdAt:new Date().toISOString()});saveTransactions(txns);els.form.reset();els.spentOnCreditCard.checked=false;if(els.creditCardUsed)els.creditCardUsed.value="";setTransactionCreditCardVisibility();setDefaultDateTime();els.categoryPreview.textContent="Category preview: Other";els.amount.focus();render();});
}

